<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -r</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .claude/commands</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> my-plugin/</span></span>
